// Java9ParserInit initializes any static state used to implement Java9Parser. By default the
// static state used to implement the parser is lazily initialized during the first call to
// NewJava9Parser(). You can call this function if you wish to initialize the static state ahead
// of time.
func Java9ParserInit() {
	staticData := &Java9ParserParserStaticData
	staticData.once.Do(java9parserParserInit)
}

// NewJava9Parser produces a new parser instance for the optional input antlr.TokenStream.
func NewJava9Parser(input antlr.TokenStream) *Java9Parser {
	Java9ParserInit()
	this := new(Java9Parser)
	this.BaseParser = antlr.NewBaseParser(input)
	staticData := &Java9ParserParserStaticData
	this.Interpreter = antlr.NewParserATNSimulator(this, staticData.atn, staticData.decisionToDFA, staticData.PredictionContextCache)
	this.RuleNames = staticData.RuleNames
	this.LiteralNames = staticData.LiteralNames
	this.SymbolicNames = staticData.SymbolicNames
	this.GrammarFileName = "Java9Parser.g4"

	return this
}

